class Node:
    def __init__(self, val=0, neighbors=None):
        self.val = val
        self.neighbors = neighbors or []
def clone_graph(node):
    if not node:
        return None
    old_to_new = {}
    def dfs(x):
        if x in old_to_new:
            return old_to_new[x]
        copy = Node(x.val)
        old_to_new[x] = copy
        for nei in x.neighbors:
            copy.neighbors.append(dfs(nei))
        return copy
    return dfs(node)

